/**
 * OURLIFE 01 - Core Setup
 * Core constants, helper functions, formatting, role checks, and safe utilities.
 */

if (!defined('ABSPATH')) {
    exit;
}

/* =====================================================
 * CONSTANTS
 * ===================================================== */

if (!defined('OURLIFE_VERSION')) {
    define('OURLIFE_VERSION', '1.0.0');
}

if (!defined('OURLIFE_PREFIX')) {
    define('OURLIFE_PREFIX', 'ourlife');
}

if (!defined('OURLIFE_CURRENCY')) {
    define('OURLIFE_CURRENCY', '₱');
}

/* =====================================================
 * ROLE SLUGS
 * ===================================================== */

if (!defined('OURLIFE_ROLE_CONSUMER')) {
    define('OURLIFE_ROLE_CONSUMER', 'ourlife_consumer');
}

if (!defined('OURLIFE_ROLE_AGENT')) {
    define('OURLIFE_ROLE_AGENT', 'ourlife_agent');
}

if (!defined('OURLIFE_ROLE_PROVIDER')) {
    define('OURLIFE_ROLE_PROVIDER', 'ourlife_provider');
}

if (!defined('OURLIFE_ROLE_ADMIN')) {
    define('OURLIFE_ROLE_ADMIN', 'ourlife_admin');
