}

/* =====================================================
 * BASIC HELPERS
 * ===================================================== */

if (!function_exists('ourlife_clean_text')) {
    function ourlife_clean_text($value) {
        return sanitize_text_field(wp_unslash($value));
    }
}

if (!function_exists('ourlife_clean_textarea')) {
    function ourlife_clean_textarea($value) {
        return sanitize_textarea_field(wp_unslash($value));
    }
}

if (!function_exists('ourlife_clean_email')) {
    function ourlife_clean_email($value) {
        return sanitize_email(wp_unslash($value));
    }
}

if (!function_exists('ourlife_clean_url')) {
    function ourlife_clean_url($value) {
        return esc_url_raw(wp_unslash($value));
    }
}

if (!function_exists('ourlife_clean_number')) {
    function ourlife_clean_number($value) {
        $value = preg_replace('/[^0-9.]/', '', (string) $value);
        return $value === '' ? 0 : floatval($value);
    }
}

/* =====================================================
 * CURRENCY FORMATTER
 * ===================================================== */

if (!function_exists('ourlife_format_price')) {
    function ourlife_format_price($amount, $show_zero = false) {
        $amount = ourlife_clean_number($amount);

        if ($amount <= 0 && !$show_zero) {
            return 'Price upon request';
        }

        return OURLIFE_CURRENCY . number_format($amount, 0);
    }
}

/* =====================================================
 * USER HELPERS
 * ===================================================== */

if (!function_exists('ourlife_current_user_has_role')) {
    function ourlife_current_user_has_role($role) {
        if (!is_user_logged_in()) {
            return false;
        }

        $user = wp_get_current_user();

        return in_array($role, (array) $user->roles, true);
    }
}

if (!function_exists('ourlife_is_consumer')) {
    function ourlife_is_consumer($user_id = 0) {
        $user = $user_id ? get_user_by('id', $user_id) : wp_get_current_user();
        return $user && in_array(OURLIFE_ROLE_CONSUMER, (array) $user->roles, true);
    }
}

if (!function_exists('ourlife_is_agent')) {
    function ourlife_is_agent($user_id = 0) {
        $user = $user_id ? get_user_by('id', $user_id) : wp_get_current_user();
        return $user && in_array(OURLIFE_ROLE_AGENT, (array) $user->roles, true);
    }
}

if (!function_exists('ourlife_is_provider')) {
    function ourlife_is_provider($user_id = 0) {
        $user = $user_id ? get_user_by('id', $user_id) : wp_get_current_user();
        return $user && in_array(OURLIFE_ROLE_PROVIDER, (array) $user->roles, true);
    }
}

if (!function_exists('ourlife_is_marketplace_admin')) {
    function ourlife_is_marketplace_admin($user_id = 0) {
        $user = $user_id ? get_user_by('id', $user_id) : wp_get_current_user();

        if (!$user) {
            return false;
        }

        return user_can($user, 'manage_options') || in_array(OURLIFE_ROLE_ADMIN, (array) $user->roles, true);
    }
}

/* =====================================================
 * META HELPERS
 * ===================================================== */

if (!function_exists('ourlife_get_meta')) {
    function ourlife_get_meta($post_id, $key, $default = '') {
        $value = get_post_meta($post_id, $key, true);
        return $value !== '' ? $value : $default;
    }
}

if (!function_exists('ourlife_update_meta')) {
    function ourlife_update_meta($post_id, $key, $value) {
        return update_post_meta($post_id, $key, $value);
    }
}

/* =====================================================
 * STATUS HELPERS
 * ===================================================== */

if (!function_exists('ourlife_status_label')) {
    function ourlife_status_label($status) {
        $labels = [
            'pending'   => 'Pending',
            'verified'  => 'Verified',
            'rejected'  => 'Rejected',
            'suspended' => 'Suspended',
            'published' => 'Published',
            'archived'  => 'Archived',
            'unclaimed' => 'Unclaimed',
        ];

        return isset($labels[$status]) ? $labels[$status] : ucfirst((string) $status);
    }
}

/* =====================================================
 * BADGE HELPERS
 * ===================================================== */

if (!function_exists('ourlife_verified_badge')) {
