/* =====================================================
 * REGISTER / SYNC ROLES
 * ===================================================== */

if (!function_exists('ourlife_register_roles')) {
    function ourlife_register_roles() {
        $roles = [
            OURLIFE_ROLE_CONSUMER => 'OURLIFE Consumer',
            OURLIFE_ROLE_AGENT    => 'OURLIFE Agent',
            OURLIFE_ROLE_COMPANY  => 'OURLIFE Company',
            OURLIFE_ROLE_ADMIN    => 'OURLIFE Admin',
        ];

        $cap_map = ourlife_role_capability_map();

        foreach ($roles as $role_slug => $role_name) {
            $caps = [];

            foreach ($cap_map[$role_slug] as $cap) {
                $caps[$cap] = true;
            }

            if (!get_role($role_slug)) {
                add_role($role_slug, $role_name, $caps);
            } else {
                $role = get_role($role_slug);

                if ($role) {
                    foreach ($caps as $cap => $grant) {
                        $role->add_cap($cap, $grant);
                    }
                }
            }
        }

        /**
         * If old provider role exists, keep it synced with Company caps.
         * This prevents old modules from failing during migration.
         */
        $provider_role = get_role('ourlife_provider');

        if ($provider_role) {
            foreach ($cap_map[OURLIFE_ROLE_COMPANY] as $cap) {
                $provider_role->add_cap($cap, true);
            }
        }
    }
}

/* =====================================================
 * ADD MARKETPLACE CAPS TO WORDPRESS ADMIN
 * ===================================================== */

if (!function_exists('ourlife_add_admin_caps')) {
    function ourlife_add_admin_caps() {
        $admin = get_role('administrator');

        if (!$admin) return;

        foreach (ourlife_role_capability_map() as $caps) {
            foreach ($caps as $cap) {
                $admin->add_cap($cap);
            }
        }

        $admin->add_cap('manage_options');
    }
}

