add_action('user_register', function ($user_id) {
    $user = get_user_by('id', $user_id);

    if (!$user) return;

    $existing_roles = (array) $user->roles;

    if (
        in_array(OURLIFE_ROLE_AGENT, $existing_roles, true) ||
        in_array(OURLIFE_ROLE_COMPANY, $existing_roles, true) ||
        in_array('ourlife_provider', $existing_roles, true) ||
        in_array(OURLIFE_ROLE_ADMIN, $existing_roles, true) ||
        in_array('administrator', $existing_roles, true)
    ) {
        return;
    }

    $user->set_role(OURLIFE_ROLE_CONSUMER);
    update_user_meta($user_id, 'ourlife_account_status', 'active');
});

