if (!function_exists('ourlife_get_user_role_label')) {
    function ourlife_get_user_role_label($user_id = 0) {
        $user = $user_id ? get_user_by('id', absint($user_id)) : wp_get_current_user();

        if (!$user) return 'Guest';

        $roles = (array) $user->roles;

        if (in_array('administrator', $roles, true)) return 'Administrator';
        if (in_array(OURLIFE_ROLE_ADMIN, $roles, true)) return 'OURLIFE Admin';
        if (in_array(OURLIFE_ROLE_COMPANY, $roles, true)) return 'Company';
        if (in_array('ourlife_provider', $roles, true)) return 'Company';
        if (in_array(OURLIFE_ROLE_AGENT, $roles, true)) return 'Agent';
        if (in_array(OURLIFE_ROLE_CONSUMER, $roles, true)) return 'Consumer';

        return 'User';
    }
}

