/* =====================================================
 * TERM INSERT HELPER
 * =====================================================
 */

if (!function_exists('ourlife_insert_term_if_missing')) {
    function ourlife_insert_term_if_missing($name, $taxonomy, $slug = '', $parent = 0) {
        if (!taxonomy_exists($taxonomy)) {
            return 0;
        }

        $existing = term_exists($slug ?: $name, $taxonomy);

        if ($existing && !is_wp_error($existing)) {
            return is_array($existing) ? intval($existing['term_id']) : intval($existing);
        }

        $args = [];

        if ($slug) {
            $args['slug'] = sanitize_title($slug);
        }

        if ($parent) {
            $args['parent'] = intval($parent);
        }

        $created = wp_insert_term($name, $taxonomy, $args);

        if (is_wp_error($created)) {
            return 0;
        }

        return intval($created['term_id']);
    }
}

