if (!function_exists('ourlife_create_database_tables')) {
    function ourlife_create_database_tables() {
        global $wpdb;

        require_once ABSPATH . 'wp-admin/includes/upgrade.php';

        $charset_collate = $wpdb->get_charset_collate();

        /* -----------------------------
         * Leads
         * ----------------------------- */

        $leads_table = ourlife_table('leads');

        $sql_leads = "CREATE TABLE {$leads_table} (
            id BIGINT(20) UNSIGNED NOT NULL AUTO_INCREMENT,
            consumer_id BIGINT(20) UNSIGNED NULL,
            lead_type VARCHAR(80) NOT NULL,
            source_type VARCHAR(80) NULL,
            source_id BIGINT(20) UNSIGNED NULL,
            listing_id BIGINT(20) UNSIGNED NULL,
            provider_id BIGINT(20) UNSIGNED NULL,
            agent_id BIGINT(20) UNSIGNED NULL,
            package_id BIGINT(20) UNSIGNED NULL,
            name VARCHAR(190) NOT NULL,
            email VARCHAR(190) NULL,
            mobile VARCHAR(80) NULL,
            city VARCHAR(120) NULL,
            province VARCHAR(120) NULL,
            message LONGTEXT NULL,
            status VARCHAR(40) NOT NULL DEFAULT 'new',
            meta LONGTEXT NULL,
            created_at DATETIME NOT NULL,
            updated_at DATETIME NULL,
            PRIMARY KEY (id),
            KEY consumer_id (consumer_id),
            KEY lead_type (lead_type),
            KEY source_type (source_type),
            KEY listing_id (listing_id),
            KEY provider_id (provider_id),
            KEY agent_id (agent_id),
            KEY package_id (package_id),
            KEY status (status),
            KEY created_at (created_at)
        ) {$charset_collate};";

        dbDelta($sql_leads);

        /* -----------------------------
         * Match Sessions
         * ----------------------------- */

        $match_sessions_table = ourlife_table('match_sessions');

        $sql_match_sessions = "CREATE TABLE {$match_sessions_table} (
            id BIGINT(20) UNSIGNED NOT NULL AUTO_INCREMENT,
            consumer_id BIGINT(20) UNSIGNED NULL,
            session_key VARCHAR(190) NOT NULL,
            journey_type VARCHAR(80) NOT NULL,
            entry_source VARCHAR(120) NULL,
            responses_json LONGTEXT NULL,
            recommended_package_id BIGINT(20) UNSIGNED NULL,
            match_score DECIMAL(8,2) NULL,
            status VARCHAR(40) NOT NULL DEFAULT 'completed',
            created_at DATETIME NOT NULL,
            PRIMARY KEY (id),
            KEY consumer_id (consumer_id),
            KEY session_key (session_key),
            KEY journey_type (journey_type),
            KEY entry_source (entry_source),
            KEY created_at (created_at)
        ) {$charset_collate};";

        dbDelta($sql_match_sessions);

        /* -----------------------------
         * Agent Affiliations
         * ----------------------------- */

        $affiliations_table = ourlife_table('agent_affiliations');

        $sql_affiliations = "CREATE TABLE {$affiliations_table} (
            id BIGINT(20) UNSIGNED NOT NULL AUTO_INCREMENT,
            agent_id BIGINT(20) UNSIGNED NOT NULL,
            provider_id BIGINT(20) UNSIGNED NOT NULL,
            status VARCHAR(40) NOT NULL DEFAULT 'pending',
            is_primary TINYINT(1) NOT NULL DEFAULT 0,
            created_at DATETIME NOT NULL,
            approved_at DATETIME NULL,
            PRIMARY KEY (id),
            KEY agent_id (agent_id),
            KEY provider_id (provider_id),
            KEY status (status),
            KEY is_primary (is_primary)
        ) {$charset_collate};";

        dbDelta($sql_affiliations);

        /* -----------------------------
         * Provider Claims
         * ----------------------------- */

        $claims_table = ourlife_table('provider_claims');

        $sql_claims = "CREATE TABLE {$claims_table} (
            id BIGINT(20) UNSIGNED NOT NULL AUTO_INCREMENT,
            provider_id BIGINT(20) UNSIGNED NOT NULL,
            user_id BIGINT(20) UNSIGNED NOT NULL,
            status VARCHAR(40) NOT NULL DEFAULT 'pending',
            documents_json LONGTEXT NULL,
            notes LONGTEXT NULL,
            created_at DATETIME NOT NULL,
            reviewed_at DATETIME NULL,
            PRIMARY KEY (id),
            KEY provider_id (provider_id),
            KEY user_id (user_id),
            KEY status (status)
        ) {$charset_collate};";

        dbDelta($sql_claims);

        /* -----------------------------
         * Saved Listings
         * ----------------------------- */

        $saved_listings_table = ourlife_table('saved_listings');

        $sql_saved_listings = "CREATE TABLE {$saved_listings_table} (
            id BIGINT(20) UNSIGNED NOT NULL AUTO_INCREMENT,
            consumer_id BIGINT(20) UNSIGNED NOT NULL,
            listing_id BIGINT(20) UNSIGNED NOT NULL,
            created_at DATETIME NOT NULL,
            PRIMARY KEY (id),
            UNIQUE KEY consumer_listing (consumer_id, listing_id),
            KEY consumer_id (consumer_id),
            KEY listing_id (listing_id)
        ) {$charset_collate};";

        dbDelta($sql_saved_listings);

        /* -----------------------------
         * Saved Agents
         * ----------------------------- */

        $saved_agents_table = ourlife_table('saved_agents');

        $sql_saved_agents = "CREATE TABLE {$saved_agents_table} (
            id BIGINT(20) UNSIGNED NOT NULL AUTO_INCREMENT,
            consumer_id BIGINT(20) UNSIGNED NOT NULL,
            agent_id BIGINT(20) UNSIGNED NOT NULL,
            created_at DATETIME NOT NULL,
            PRIMARY KEY (id),
            UNIQUE KEY consumer_agent (consumer_id, agent_id),
            KEY consumer_id (consumer_id),
            KEY agent_id (agent_id)
        ) {$charset_collate};";

        dbDelta($sql_saved_agents);

        update_option('ourlife_db_version', OURLIFE_VERSION);
        update_option('ourlife_db_created_at', current_time('mysql'));
    }
}

