                'recommended_package_id' => $data['recommended_package_id'] ? absint($data['recommended_package_id']) : null,
                'match_score'            => $data['match_score'] !== null ? floatval($data['match_score']) : null,
                'status'                 => sanitize_key($data['status']),
                'created_at'             => current_time('mysql'),
