add_action('save_post_' . OURLIFE_CPT_PROVIDER, function ($post_id) {
    if (
        !isset($_POST['_ourlife_provider_nonce']) ||
        !wp_verify_nonce(sanitize_text_field(wp_unslash($_POST['_ourlife_provider_nonce'])), 'ourlife_save_provider_details')
    ) {
        return;
    }

    if (defined('DOING_AUTOSAVE') && DOING_AUTOSAVE) {
        return;
    }

    if (!current_user_can('edit_post', $post_id)) {
        return;
    }

    $text_fields = [
        '_provider_type',
        '_address',
        '_city',
        '_province',
        '_contact_number',
        '_verification_status',
        '_claim_status',
    ];

    foreach ($text_fields as $field) {
        if (isset($_POST[$field])) {
            update_post_meta($post_id, $field, sanitize_text_field(wp_unslash($_POST[$field])));
        }
    }

    if (isset($_POST['_provider_type'])) {
        update_post_meta($post_id, '_company_type', sanitize_text_field(wp_unslash($_POST['_provider_type'])));
    }

    if (isset($_POST['_business_description'])) {
        update_post_meta($post_id, '_business_description', sanitize_textarea_field(wp_unslash($_POST['_business_description'])));
    }

    if (isset($_POST['_email'])) {
        update_post_meta($post_id, '_email', sanitize_email(wp_unslash($_POST['_email'])));
    }

    if (isset($_POST['_website'])) {
        update_post_meta($post_id, '_website', esc_url_raw(wp_unslash($_POST['_website'])));
    }

    if (!get_post_meta($post_id, '_created_by_user', true)) {
        update_post_meta($post_id, '_created_by_user', get_current_user_id());
    }
});

