/* =====================================================
 * SAVE LISTING META
 * =====================================================
 */

add_action('save_post_' . OURLIFE_CPT_LISTING, function ($post_id) {
    if (
        !isset($_POST['_ourlife_listing_nonce']) ||
        !wp_verify_nonce(sanitize_text_field(wp_unslash($_POST['_ourlife_listing_nonce'])), 'ourlife_save_listing_details')
    ) {
        return;
    }

    if (defined('DOING_AUTOSAVE') && DOING_AUTOSAVE) {
        return;
    }

    if (!current_user_can('edit_post', $post_id)) {
        return;
    }

    $int_fields = [
        '_provider_id',
        '_agent_id',
    ];

    foreach ($int_fields as $field) {
        if (isset($_POST[$field])) {
            update_post_meta($post_id, $field, absint($_POST[$field]));
        }
    }

    $text_fields = [
        '_owner_type',
        '_location_city',
        '_location_province',
        '_availability',
        '_listing_status',
        '_featured_status',
        '_address',
        '_capacity',
    ];

    foreach ($text_fields as $field) {
        if (isset($_POST[$field])) {
            update_post_meta($post_id, $field, sanitize_text_field(wp_unslash($_POST[$field])));
        }
    }

    if (isset($_POST['_price'])) {
        update_post_meta($post_id, '_price', ourlife_clean_number($_POST['_price']));
    }

    if (isset($_POST['_monthly_payment'])) {
        update_post_meta($post_id, '_monthly_payment', ourlife_clean_number($_POST['_monthly_payment']));
    }

    if (isset($_POST['_features'])) {
        update_post_meta($post_id, '_features', sanitize_textarea_field(wp_unslash($_POST['_features'])));
    }

    update_post_meta($post_id, '_last_updated', current_time('mysql'));

    if (!get_post_meta($post_id, '_owner_user_id', true)) {
        update_post_meta($post_id, '_owner_user_id', get_current_user_id());
    }
});

