/* =====================================================
 * LISTING DIRECTORY SHORTCODE
 * Usage:
 * [ourlife_listing_directory]
 * Optional:
 * [ourlife_listing_directory category="columbarium" limit="9"]
 * =====================================================
 */

add_shortcode('ourlife_listing_directory', function ($atts) {
    $atts = shortcode_atts([
        'limit'    => 12,
        'category' => '',
        'type'     => '',
        'featured' => '',
    ], $atts);

    $tax_query = [];

    if (!empty($atts['category'])) {
        $tax_query[] = [
            'taxonomy' => OURLIFE_TAX_LISTING_CATEGORY,
            'field'    => 'slug',
            'terms'    => sanitize_title($atts['category']),
        ];
    }

    if (!empty($atts['type'])) {
        $tax_query[] = [
            'taxonomy' => OURLIFE_TAX_LISTING_TYPE,
            'field'    => 'slug',
            'terms'    => sanitize_title($atts['type']),
        ];
    }

    $meta_query = [];

    if (!empty($atts['featured'])) {
        $meta_query[] = [
            'key'   => '_featured_status',
            'value' => sanitize_key($atts['featured']),
        ];
    }

    $args = [
        'post_type'      => OURLIFE_CPT_LISTING,
        'posts_per_page' => absint($atts['limit']),
        'post_status'    => 'publish',
    ];

    if (!empty($tax_query)) {
        $args['tax_query'] = $tax_query;
    }

    if (!empty($meta_query)) {
        $args['meta_query'] = $meta_query;
    }

    $q = new WP_Query($args);

    if (!$q->have_posts()) {
        return '<div class="ourlife-card">No listings found.</div>';
    }

    ob_start();
    ?>

    <div class="ourlife-listing-directory">
        <div style="display:grid;grid-template-columns:repeat(auto-fit,minmax(260px,1fr));gap:20px;">
            <?php while ($q->have_posts()): $q->the_post(); ?>
                <?php echo ourlife_render_listing_card(get_the_ID()); ?>
            <?php endwhile; wp_reset_postdata(); ?>
        </div>
    </div>

    <?php
    return ob_get_clean();
});

