/* =====================================================
 * SAFE LISTING RELATION HELPERS
 * ===================================================== */

if (!function_exists('ourlife09_get_listing_company_id')) {
    function ourlife09_get_listing_company_id($listing_id) {
        $listing_id = absint($listing_id);

        if (!$listing_id) {
            return 0;
        }

        if (function_exists('ourlife_get_listing_provider_id')) {
            return absint(ourlife_get_listing_provider_id($listing_id));
        }

        $company_id = absint(get_post_meta($listing_id, '_company_id', true));

        if (!$company_id) {
            $company_id = absint(get_post_meta($listing_id, '_provider_id', true));
        }

        return $company_id;
    }
}

if (!function_exists('ourlife09_get_listing_agent_id')) {
    function ourlife09_get_listing_agent_id($listing_id) {
        $listing_id = absint($listing_id);

        if (!$listing_id) {
            return 0;
        }

        if (function_exists('ourlife_get_listing_agent_id')) {
            return absint(ourlife_get_listing_agent_id($listing_id));
        }

        return absint(get_post_meta($listing_id, '_agent_id', true));
    }
}

/* =====================================================
 * ROUTING HELPER
 * ===================================================== */

if (!function_exists('ourlife_get_lead_recipients')) {
    function ourlife_get_lead_recipients($data = []) {
        $recipients = [];

        $company_id  = !empty($data['company_id']) ? absint($data['company_id']) : 0;
        $provider_id = !empty($data['provider_id']) ? absint($data['provider_id']) : 0;
        $agent_id    = !empty($data['agent_id']) ? absint($data['agent_id']) : 0;
        $listing_id  = !empty($data['listing_id']) ? absint($data['listing_id']) : 0;

        if (!$company_id && $provider_id) {
            $company_id = $provider_id;
        }

        if ($listing_id && get_post_type($listing_id) === OURLIFE_CPT_LISTING) {
            if (!$company_id) {
                $company_id = ourlife09_get_listing_company_id($listing_id);
            }

            if (!$agent_id) {
                $agent_id = ourlife09_get_listing_agent_id($listing_id);
            }
        }

        if ($company_id && get_post_type($company_id) === OURLIFE_CPT_PROVIDER) {
            $company_email = get_post_meta($company_id, '_email', true);

            if ($company_email && is_email($company_email)) {
                $recipients[] = $company_email;
            }
        }

        if ($agent_id && get_post_type($agent_id) === OURLIFE_CPT_AGENT) {
            $agent_email = get_post_meta($agent_id, '_email', true);

            if ($agent_email && is_email($agent_email)) {
                $recipients[] = $agent_email;
            }
        }

        $admin_email = get_option('admin_email');

        if ($admin_email && is_email($admin_email)) {
            $recipients[] = $admin_email;
        }

        return array_values(array_unique(array_filter($recipients)));
    }
}

/* =====================================================
 * SEND LEAD NOTIFICATIONS
 * ===================================================== */

if (!function_exists('ourlife_send_lead_notifications')) {
    function ourlife_send_lead_notifications($lead_id, $data = []) {
        $recipients = ourlife_get_lead_recipients($data);

        if (empty($recipients)) {
            return false;
        }

        $subject = 'New OURLIFE.PH Inquiry #' . intval($lead_id);

        $message  = "A new inquiry has been submitted on OURLIFE.PH.\n\n";
        $message .= "Lead ID: " . intval($lead_id) . "\n";
        $message .= "Lead Type: " . ourlife_lead_type_label($data['lead_type'] ?? 'general') . "\n";
        $message .= "Name: " . sanitize_text_field($data['name'] ?? '') . "\n";
        $message .= "Email: " . sanitize_email($data['email'] ?? '') . "\n";
        $message .= "Mobile: " . sanitize_text_field($data['mobile'] ?? '') . "\n";
        $message .= "Location: " . sanitize_text_field($data['city'] ?? '') . ', ' . sanitize_text_field($data['province'] ?? '') . "\n\n";
        $message .= "Message:\n" . sanitize_textarea_field($data['message'] ?? '') . "\n\n";

        if (!empty($data['listing_id'])) {
            $message .= "Listing: " . get_the_title(absint($data['listing_id'])) . "\n";
            $message .= "Listing URL: " . get_permalink(absint($data['listing_id'])) . "\n\n";
        }

        $company_id = !empty($data['company_id'])
            ? absint($data['company_id'])
            : (!empty($data['provider_id']) ? absint($data['provider_id']) : 0);

        if ($company_id) {
            $message .= "Company: " . get_the_title($company_id) . "\n";
        }

        if (!empty($data['agent_id'])) {
            $message .= "Agent: " . get_the_title(absint($data['agent_id'])) . "\n";
        }

        $message .= "\nPlease follow up with the consumer as soon as possible.";

        return wp_mail($recipients, $subject, $message);
    }
}

/* =====================================================
 * HANDLE LEAD FORM SUBMISSION
 * ===================================================== */

add_action('init', function () {
    if (empty($_POST['ourlife_lead_action']) || $_POST['ourlife_lead_action'] !== 'submit_lead') {
        return;
    }

    if (!function_exists('ourlife_verify_nonce') || !ourlife_verify_nonce('ourlife_submit_lead')) {
        wp_die('Security check failed.');
    }

    $listing_id  = isset($_POST['listing_id']) ? absint($_POST['listing_id']) : 0;
    $company_id  = isset($_POST['company_id']) ? absint($_POST['company_id']) : 0;
    $provider_id = isset($_POST['provider_id']) ? absint($_POST['provider_id']) : 0;
    $agent_id    = isset($_POST['agent_id']) ? absint($_POST['agent_id']) : 0;
    $package_id  = isset($_POST['package_id']) ? absint($_POST['package_id']) : 0;

    if (!$company_id && $provider_id) {
        $company_id = $provider_id;
    }

    if ($listing_id && get_post_type($listing_id) === OURLIFE_CPT_LISTING) {
        if (!$company_id) {
            $company_id = ourlife09_get_listing_company_id($listing_id);
        }

        if (!$agent_id) {
            $agent_id = ourlife09_get_listing_agent_id($listing_id);
        }
    }

    $lead_type = isset($_POST['lead_type'])
        ? sanitize_key(wp_unslash($_POST['lead_type']))
        : 'general';

    /**
     * Keep legacy lead type in DB if other modules expect provider_inquiry.
     * Display labels convert it to Company Inquiry.
     */
    if ($lead_type === 'company_inquiry') {
        $lead_type = 'provider_inquiry';
    }

    $source_type = isset($_POST['source_type'])
        ? sanitize_key(wp_unslash($_POST['source_type']))
        : '';

    if ($source_type === 'company') {
        $source_type = 'provider';
    }

    $data = [
        'consumer_id' => get_current_user_id() ?: null,
        'lead_type'   => $lead_type,
        'source_type' => $source_type,
        'source_id'   => isset($_POST['source_id']) ? absint($_POST['source_id']) : null,
        'listing_id'  => $listing_id ?: null,

        /**
         * DB compatibility.
         */
        'provider_id' => $company_id ?: null,

        /**
         * Runtime alias.
         */
        'company_id'  => $company_id ?: null,

        'agent_id'    => $agent_id ?: null,
        'package_id'  => $package_id ?: null,
        'name'        => isset($_POST['name']) ? sanitize_text_field(wp_unslash($_POST['name'])) : '',
        'email'       => isset($_POST['email']) ? sanitize_email(wp_unslash($_POST['email'])) : '',
        'mobile'      => isset($_POST['mobile']) ? sanitize_text_field(wp_unslash($_POST['mobile'])) : '',
        'city'        => isset($_POST['city']) ? sanitize_text_field(wp_unslash($_POST['city'])) : '',
        'province'    => isset($_POST['province']) ? sanitize_text_field(wp_unslash($_POST['province'])) : '',
        'message'     => isset($_POST['message']) ? sanitize_textarea_field(wp_unslash($_POST['message'])) : '',
        'status'      => 'new',
        'meta'        => [
            'ip'         => isset($_SERVER['REMOTE_ADDR']) ? sanitize_text_field(wp_unslash($_SERVER['REMOTE_ADDR'])) : '',
            'user_agent' => isset($_SERVER['HTTP_USER_AGENT']) ? sanitize_text_field(wp_unslash($_SERVER['HTTP_USER_AGENT'])) : '',
            'referrer'   => wp_get_referer(),
        ],
    ];

    if (empty($data['name']) || (empty($data['email']) && empty($data['mobile']))) {
        wp_die('Please provide your name and either an email or mobile number.');
    }

    if (!function_exists('ourlife_insert_lead')) {
        wp_die('Lead database is not available.');
    }

    $lead_id = ourlife_insert_lead($data);

    if (!$lead_id) {
        wp_die('Unable to submit inquiry. Please try again.');
    }

    ourlife_send_lead_notifications($lead_id, $data);

    $redirect = add_query_arg(
        [
            'ourlife_inquiry' => 'success',
            'lead_id'         => $lead_id,
        ],
        wp_get_referer() ?: home_url('/')
    );

    wp_safe_redirect($redirect);
    exit;
});

