/* =====================================================
 * MATCH RESPONSE SANITIZER
 * ===================================================== */

if (!function_exists('ourlife_sanitize_match_responses')) {
    function ourlife_sanitize_match_responses($raw = []) {
        $clean = [];

        $fields = [
            'journey_type',
            'entry_source',
            'planning_for',
            'arrangement_preference',
            'planning_for_person',
            'need_type',
            'timeline',
            'budget_range',
            'agent_preference',
            'city',
            'province',
        ];

        foreach ($fields as $field) {
            if (isset($raw[$field])) {
                $clean[$field] = sanitize_text_field(wp_unslash($raw[$field]));
            }
        }

        return $clean;
    }
}

/* =====================================================
 * HANDLE MATCH SUBMISSION
 * ===================================================== */

add_action('init', function () {
    if (empty($_POST['ourlife_match_action']) || $_POST['ourlife_match_action'] !== 'submit_match') {
        return;
    }

    if (!function_exists('ourlife_verify_nonce') || !ourlife_verify_nonce('ourlife_submit_match')) {
        wp_die('Security check failed.');
    }

    if (!function_exists('ourlife_insert_match_session')) {
        wp_die('Match system database is not available.');
    }

    $responses = ourlife_sanitize_match_responses($_POST);

    $journey_type = !empty($responses['journey_type'])
        ? sanitize_key($responses['journey_type'])
        : 'planning_ahead';

    $entry_source = !empty($responses['entry_source'])
        ? sanitize_key($responses['entry_source'])
        : 'direct_match_page';

    $session_key = wp_generate_uuid4();

    $session_id = ourlife_insert_match_session([
        'consumer_id'    => get_current_user_id() ?: null,
        'session_key'    => $session_key,
        'journey_type'   => $journey_type,
        'entry_source'   => $entry_source,
        'responses_json' => $responses,
        'match_score'    => 0,
        'status'         => 'completed',
    ]);

    if (!$session_id) {
        wp_die('Unable to process match. Please try again.');
    }

    $results_page = get_page_by_path('ourlife-match-results');

    $redirect_url = $results_page
        ? get_permalink($results_page->ID)
        : home_url('/ourlife-match-results/');

    $redirect_url = add_query_arg([
        'session' => rawurlencode($session_key),
    ], $redirect_url);

    wp_safe_redirect($redirect_url);
    exit;
});

