    <script>
        (function () {
            const form = document.getElementById('ourlifeMatchForm');
            if (!form) return;

            const steps = Array.from(form.querySelectorAll('.ourlife-match-step'));
            const nextBtn = document.getElementById('ourlifeMatchNext');
            const prevBtn = document.getElementById('ourlifeMatchPrev');
            const submitBtn = document.getElementById('ourlifeMatchSubmit');
            const progress = document.getElementById('ourlifeMatchProgress');

            let currentStep = 1;
            const totalSteps = 7;

            function getJourney() {
                const selected = form.querySelector('input[name="journey_type"]:checked');
                return selected ? selected.value : '';
            }

            function visibleStepElement(stepNumber) {
                const journey = getJourney();
                const candidates = steps.filter(step => parseInt(step.dataset.step, 10) === stepNumber);

                if (candidates.length <= 1) {
                    return candidates[0];
                }

                return candidates.find(step => step.dataset.journey === journey) || candidates[0];
            }

            function showStep(stepNumber) {
                steps.forEach(step => {
                    step.classList.remove('active');
                });

                const step = visibleStepElement(stepNumber);

                if (step) {
                    step.classList.add('active');
                }

                currentStep = stepNumber;

                prevBtn.style.display = currentStep > 1 ? 'inline-flex' : 'none';
                nextBtn.style.display = currentStep < totalSteps ? 'inline-flex' : 'none';
                submitBtn.style.display = currentStep === totalSteps ? 'inline-flex' : 'none';

                progress.style.width = Math.round((currentStep / totalSteps) * 100) + '%';
            }

            function validateCurrentStep() {
                const step = visibleStepElement(currentStep);

                if (!step) {
                    return true;
                }

                const radios = Array.from(step.querySelectorAll('input[type="radio"]'));

                if (!radios.length) {
                    return true;
                }

                const names = [...new Set(radios.map(r => r.name))];

                for (const name of names) {
                    const checked = step.querySelector('input[name="' + name + '"]:checked');

                    if (!checked) {
                        alert('Please select an option to continue.');
                        return false;
                    }
                }

                return true;
            }

            nextBtn.addEventListener('click', function () {
                if (!validateCurrentStep()) {
                    return;
                }

                if (currentStep < totalSteps) {
                    showStep(currentStep + 1);
                }
            });

            prevBtn.addEventListener('click', function () {
                if (currentStep > 1) {
                    showStep(currentStep - 1);
                }
            });

            form.addEventListener('change', function (event) {
                if (event.target.name === 'journey_type' && currentStep === 2) {
                    showStep(2);
                }
            });

            showStep(1);
        })();
    </script>

