if (!function_exists('ourlife_get_match_session_by_key')) {
    function ourlife_get_match_session_by_key($session_key) {
        global $wpdb;

        $session_key = sanitize_text_field($session_key);

        if (!$session_key || !function_exists('ourlife_table')) {
            return null;
        }

        $table = ourlife_table('match_sessions');

        return $wpdb->get_row(
            $wpdb->prepare(
                "SELECT * FROM {$table} WHERE session_key = %s LIMIT 1",
                $session_key
            )
        );
    }
}

/* =====================================================
 * NORMALIZE MATCH RESPONSES
 * ===================================================== */

if (!function_exists('ourlife_decode_match_responses')) {
    function ourlife_decode_match_responses($session) {
        if (!$session || empty($session->responses_json)) {
            return [];
        }

        $responses = json_decode($session->responses_json, true);

        return is_array($responses) ? $responses : [];
    }
}

/* =====================================================
 * MATCH BUDGET TO PRICE RANGE
 * ===================================================== */

if (!function_exists('ourlife_budget_to_price_limits')) {
    function ourlife_budget_to_price_limits($budget_range) {
        switch ($budget_range) {
            case 'under_50000':
                return [0, 50000];

            case '50000_150000':
                return [50000, 150000];

            case '150000_500000':
                return [150000, 500000];

            case '500000_plus':
                return [500000, PHP_INT_MAX];

            default:
                return [0, PHP_INT_MAX];
        }
    }
}

/* =====================================================
 * MATCH CATEGORY TO LISTING TYPE SLUGS
 * ===================================================== */

if (!function_exists('ourlife_match_listing_type_slugs')) {
    function ourlife_match_listing_type_slugs($responses) {
        $journey = $responses['journey_type'] ?? 'planning_ahead';

        $types = [];

        if ($journey === 'planning_ahead') {
            $planning_for = $responses['planning_for'] ?? 'not_sure';
            $arrangement  = $responses['arrangement_preference'] ?? 'not_sure';

            if ($planning_for === 'memorial_property' || $arrangement === 'burial') {
                $types = array_merge($types, [
                    'memorial-lot',
                    'family-lot',
                    'estate-lot',
                    'mausoleum',
                ]);
            }

            if ($planning_for === 'columbarium' || $arrangement === 'cremation') {
                $types = array_merge($types, [
                    'single-niche',
                    'companion-niche',
                    'family-niche',
                ]);
            }

            if ($planning_for === 'funeral_plan') {
                $types[] = 'funeral-plan';
            }

            if ($planning_for === 'memorial_plan') {
                $types[] = 'memorial-plan';
            }

            if ($planning_for === 'cremation_plan') {
                $types[] = 'cremation-plan';
            }

            if ($planning_for === 'not_sure') {
                $types = array_merge($types, [
                    'memorial-lot',
                    'family-lot',
                    'single-niche',
                    'companion-niche',
                    'family-niche',
                    'funeral-plan',
                    'memorial-plan',
                    'cremation-plan',
                ]);
            }
        }

        if ($journey === 'need_help_now') {
            $need_type = $responses['need_type'] ?? 'not_sure';

            $map = [
                'funeral_service'   => ['funeral-service'],
                'cremation_service' => ['cremation-service'],
                'columbarium'       => ['single-niche', 'companion-niche', 'family-niche'],
                'flowers_wreaths'   => ['flowers-wreaths'],
                'urn'               => ['urn'],
                'not_sure'          => [
                    'funeral-service',
                    'cremation-service',
                    'single-niche',
                    'companion-niche',
                    'family-niche',
                    'flowers-wreaths',
                    'urn',
                ],
            ];

            $types = $map[$need_type] ?? $map['not_sure'];
        }

        return array_values(array_unique(array_filter($types)));
    }
}

/* =====================================================
 * SAFE LISTING COMPANY / AGENT HELPERS
 * ===================================================== */

if (!function_exists('ourlife11_get_listing_company_id')) {
    function ourlife11_get_listing_company_id($listing_id) {
        $listing_id = absint($listing_id);

        if (!$listing_id) {
            return 0;
        }

        if (function_exists('ourlife_get_listing_provider_id')) {
            return absint(ourlife_get_listing_provider_id($listing_id));
        }

        $company_id = absint(get_post_meta($listing_id, '_company_id', true));

        if (!$company_id) {
            $company_id = absint(get_post_meta($listing_id, '_provider_id', true));
        }

        return $company_id;
    }
}

if (!function_exists('ourlife11_get_listing_agent_id')) {
    function ourlife11_get_listing_agent_id($listing_id) {
        $listing_id = absint($listing_id);

        if (!$listing_id) {
            return 0;
        }

        if (function_exists('ourlife_get_listing_agent_id')) {
            return absint(ourlife_get_listing_agent_id($listing_id));
        }

        return absint(get_post_meta($listing_id, '_agent_id', true));
    }
}

/* =====================================================
 * SCORE A LISTING
 * ===================================================== */

if (!function_exists('ourlife_score_listing')) {
    function ourlife_score_listing($listing_id, $responses) {
        $listing_id = absint($listing_id);

        if (!$listing_id) {
            return 0;
        }

        $score = 0;

        $city     = strtolower(trim(get_post_meta($listing_id, '_location_city', true)));
        $province = strtolower(trim(get_post_meta($listing_id, '_location_province', true)));

        $target_city     = strtolower(trim($responses['city'] ?? ''));
        $target_province = strtolower(trim($responses['province'] ?? ''));

        $price = floatval(get_post_meta($listing_id, '_price', true));
        [$min_price, $max_price] = ourlife_budget_to_price_limits($responses['budget_range'] ?? 'not_sure');

        $availability = get_post_meta($listing_id, '_availability', true);
        $company_id   = ourlife11_get_listing_company_id($listing_id);
        $agent_id     = ourlife11_get_listing_agent_id($listing_id);

        /* Location score: 35 */
        if ($target_city && $city && $target_city === $city) {
            $score += 35;
        } elseif ($target_province && $province && $target_province === $province) {
            $score += 25;
        } elseif (!$target_city && !$target_province) {
            $score += 15;
        }

        /* Category score: 30 */
        $target_types = ourlife_match_listing_type_slugs($responses);

        if (!empty($target_types)) {
            $terms = wp_get_post_terms($listing_id, OURLIFE_TAX_LISTING_TYPE, ['fields' => 'slugs']);

            if (!is_wp_error($terms) && array_intersect($target_types, $terms)) {
                $score += 30;
            }
        }

        /* Budget score: 20 */
        if ($price > 0 && $price >= $min_price && $price <= $max_price) {
            $score += 20;
        } elseif ($price <= 0 || ($responses['budget_range'] ?? '') === 'not_sure') {
            $score += 10;
        }

        /* Availability score: 10 */
        if ($availability === 'available') {
            $score += 10;
        } elseif ($availability === 'limited') {
            $score += 7;
        } elseif ($availability === 'upon_request') {
            $score += 4;
        }

        /* Verification score: 5 */
        if ($company_id && get_post_meta($company_id, '_verification_status', true) === 'verified') {
            $score += 3;
        }

        if ($agent_id && get_post_meta($agent_id, '_verification_status', true) === 'verified') {
            $score += 2;
        }

        return min(100, $score);
    }
}

/* =====================================================
 * GET RECOMMENDED LISTINGS
 * ===================================================== */

if (!function_exists('ourlife_get_recommended_listings')) {
    function ourlife_get_recommended_listings($responses, $limit = 6) {
        $target_types = ourlife_match_listing_type_slugs($responses);

        $args = [
            'post_type'      => OURLIFE_CPT_LISTING,
            'posts_per_page' => 50,
            'post_status'    => 'publish',
        ];

        if (!empty($target_types)) {
            $args['tax_query'] = [
                [
                    'taxonomy' => OURLIFE_TAX_LISTING_TYPE,
                    'field'    => 'slug',
                    'terms'    => $target_types,
                ],
            ];
        }

        $query = new WP_Query($args);

        $scored = [];

        if ($query->have_posts()) {
            while ($query->have_posts()) {
                $query->the_post();

                $listing_id = get_the_ID();

                $scored[] = [
                    'id'    => $listing_id,
                    'score' => ourlife_score_listing($listing_id, $responses),
                ];
            }

            wp_reset_postdata();
        }

        usort($scored, function ($a, $b) {
            return $b['score'] <=> $a['score'];
        });

        return array_slice($scored, 0, absint($limit));
    }
}

/* =====================================================
 * GET RECOMMENDED COMPANIES
 * Legacy function name retained.
 * ===================================================== */

if (!function_exists('ourlife_get_recommended_providers_from_listings')) {
    function ourlife_get_recommended_providers_from_listings($recommended_listings, $limit = 4) {
        $companies = [];

        foreach ((array) $recommended_listings as $item) {
            if (empty($item['id'])) {
                continue;
            }

            $company_id = ourlife11_get_listing_company_id($item['id']);

            if ($company_id && get_post_type($company_id) === OURLIFE_CPT_PROVIDER) {
                $companies[$company_id] = $company_id;
            }
        }

        return array_slice(array_values($companies), 0, absint($limit));
    }
}

if (!function_exists('ourlife_get_recommended_companies_from_listings')) {
    function ourlife_get_recommended_companies_from_listings($recommended_listings, $limit = 4) {
        return ourlife_get_recommended_providers_from_listings($recommended_listings, $limit);
    }
}

/* =====================================================
 * GET RECOMMENDED AGENTS
 * ===================================================== */

if (!function_exists('ourlife_get_recommended_agents_from_listings')) {
    function ourlife_get_recommended_agents_from_listings($recommended_listings, $limit = 4) {
        $agents = [];

        foreach ((array) $recommended_listings as $item) {
            if (empty($item['id'])) {
                continue;
            }

            $agent_id = ourlife11_get_listing_agent_id($item['id']);

            if ($agent_id && get_post_type($agent_id) === OURLIFE_CPT_AGENT) {
                $agents[$agent_id] = $agent_id;
            }
        }

        return array_slice(array_values($agents), 0, absint($limit));
    }
}

/* =====================================================
 * BUILD RECOMMENDED PACKAGE SUMMARY
 * ===================================================== */

if (!function_exists('ourlife_build_package_summary')) {
    function ourlife_build_package_summary($responses, $recommended_listings) {
        $journey = $responses['journey_type'] ?? 'planning_ahead';

        $package_name = $journey === 'need_help_now'
            ? 'Immediate Assistance Package'
            : 'Planning Ahead Package';

        $items = [];

        foreach (array_slice((array) $recommended_listings, 0, 3) as $item) {
            if (!empty($item['id'])) {
                $items[] = get_the_title($item['id']);
            }
        }

        if (empty($items)) {
            $items[] = 'Recommended marketplace options';
        }

        $estimated_budget = 'Based on selected preferences';

        if (!empty($recommended_listings[0]['id'])) {
            $price = get_post_meta($recommended_listings[0]['id'], '_price', true);

            if ($price) {
                $estimated_budget = 'Starts at ' . ourlife_format_price($price);
            }
        }

        return [
            'name'             => $package_name,
            'items'            => $items,
            'estimated_budget' => $estimated_budget,
        ];
    }
}

