 * ===================================================== */

if (!function_exists('ourlife_get_terms_for_filter')) {
    function ourlife_get_terms_for_filter($taxonomy) {
        if (!taxonomy_exists($taxonomy)) {
            return [];
        }

        $terms = get_terms([
            'taxonomy'   => $taxonomy,
            'hide_empty' => false,
            'orderby'    => 'name',
            'order'      => 'ASC',
        ]);

        return is_wp_error($terms) ? [] : $terms;
    }
}

