/* =====================================================
 * LISTING DIRECTORY WITH FILTERS
 * Usage:
 * [ourlife_listing_search]
 * [ourlife_listing_search category="columbarium"]
 * ===================================================== */

add_shortcode('ourlife_listing_search', function ($atts) {
    $atts = shortcode_atts([
        'limit'    => 12,
        'category' => '',
    ], $atts);

    $keyword  = ourlife_get_filter_value('ol_keyword');
    $category = ourlife_get_filter_value('ol_category', sanitize_title($atts['category']));
    $type     = ourlife_get_filter_value('ol_type');
    $location = ourlife_get_filter_value('ol_location');
    $budget   = ourlife_get_filter_value('ol_budget');

    $tax_query = [];

    if ($category) {
        $tax_query[] = [
            'taxonomy' => OURLIFE_TAX_LISTING_CATEGORY,
            'field'    => 'slug',
            'terms'    => $category,
        ];
    }

    if ($type) {
        $tax_query[] = [
            'taxonomy' => OURLIFE_TAX_LISTING_TYPE,
            'field'    => 'slug',
            'terms'    => $type,
        ];
    }

    if ($budget) {
        $tax_query[] = [
            'taxonomy' => OURLIFE_TAX_PRICE_RANGE,
            'field'    => 'slug',
            'terms'    => $budget,
        ];
    }

    $meta_query = [];

    if ($location) {
        $meta_query[] = [
            'relation' => 'OR',
            [
                'key'     => '_location_city',
                'value'   => $location,
                'compare' => 'LIKE',
            ],
            [
                'key'     => '_location_province',
                'value'   => $location,
                'compare' => 'LIKE',
