/* =====================================================
 * AUTO INJECT CONTENT INTO SINGLE PAGES
 * ===================================================== */

add_filter('the_content', function ($content) {

    if (is_admin() || !is_main_query() || !in_the_loop()) {
        return $content;
    }

    $post_id   = get_the_ID();
    $post_type = get_post_type($post_id);

    if ($post_type === OURLIFE_CPT_PROVIDER) {
        return ourlife_render_provider_single_template($post_id);
    }

    if ($post_type === OURLIFE_CPT_AGENT) {
        return ourlife_render_agent_single_template($post_id);
    }

    if ($post_type === OURLIFE_CPT_LISTING) {
        return ourlife_render_listing_single_template($post_id);
    }

    return $content;
}, 20);

