add_shortcode('ourlife_similar_listings', function ($atts) {
    $atts = shortcode_atts([
        'id'    => 0,
        'limit' => 4,
    ], $atts);

    $listing_id = absint($atts['id']);

    if (!$listing_id && is_singular(OURLIFE_CPT_LISTING)) {
        $listing_id = get_the_ID();
    }

    if (!$listing_id || get_post_type($listing_id) !== OURLIFE_CPT_LISTING) {
        return '';
    }

    $terms = wp_get_post_terms($listing_id, OURLIFE_TAX_LISTING_TYPE, [
        'fields' => 'ids',
    ]);

    $args = [
        'post_type'      => OURLIFE_CPT_LISTING,
        'posts_per_page' => absint($atts['limit']),
        'post_status'    => 'publish',
        'post__not_in'   => [$listing_id],
    ];

    if (!is_wp_error($terms) && !empty($terms)) {
        $args['tax_query'] = [
            [
                'taxonomy' => OURLIFE_TAX_LISTING_TYPE,
                'field'    => 'term_id',
                'terms'    => $terms,
            ],
        ];
    }

    $q = new WP_Query($args);

    if (!$q->have_posts()) {
        return '';
    }

    ob_start();
    ?>

    <div class="ourlife-card">
        <h3 style="margin-top:0;">Similar Listings</h3>

        <div style="display:grid;grid-template-columns:repeat(auto-fit,minmax(240px,1fr));gap:20px;">
            <?php while ($q->have_posts()): $q->the_post(); ?>
                <?php echo ourlife_render_listing_card(get_the_ID()); ?>
            <?php endwhile; wp_reset_postdata(); ?>
        </div>
    </div>

    <?php
    return ob_get_clean();
});

