 * ===================================================== */

add_action('wp_footer', function () {
    ?>
    <script>
        document.addEventListener('DOMContentLoaded', function () {
            const provinceApi = 'https://psgc.gitlab.io/api/provinces/';
            const ncrOption = { code: '130000000', name: 'Metro Manila / NCR', type: 'region' };

            function normalizeName(value) {
                return String(value || '').toLowerCase().replace('/ ncr', '').replace('ncr', '').replace(/\s+/g, ' ').trim();
            }

            async function fetchJson(url) {
                const response = await fetch(url);
                if (!response.ok) throw new Error('Location API error');
                return await response.json();
            }

            function sortByName(items) {
                return items.sort((a, b) => a.name.localeCompare(b.name));
            }

            function findOptionByDefaults(select, defaultCode, defaultName) {
                let matched = null;
                const normalizedDefaultName = normalizeName(defaultName);

                Array.from(select.options).forEach(function (option) {
                    const optionName = option.dataset.name || option.textContent || '';
                    const normalizedOptionName = normalizeName(optionName);

                    if (defaultCode && option.value === defaultCode) matched = option;
                    if (!matched && normalizedDefaultName && normalizedOptionName === normalizedDefaultName) matched = option;
                    if (!matched && normalizedDefaultName && normalizedOptionName.includes(normalizedDefaultName)) matched = option;
                    if (!matched && normalizedDefaultName && normalizedDefaultName.includes(normalizedOptionName)) matched = option;
                });

                return matched;
            }

            async function loadProvinces(wrapper) {
                const provinceSelect = wrapper.querySelector('.ourlife-province-select');
                if (!provinceSelect || provinceSelect.dataset.loaded === '1') return;

                const defaultProvinceName = wrapper.dataset.defaultProvinceName || '';
                const defaultProvinceCode = wrapper.dataset.defaultProvinceCode || '';

                provinceSelect.innerHTML = '<option value="">Loading provinces...</option>';

                try {
                    let provinces = await fetchJson(provinceApi);
                    provinces = sortByName(provinces);

                    provinceSelect.innerHTML = '<option value="">Select Province</option>';

                    const ncr = document.createElement('option');
                    ncr.value = ncrOption.code;
                    ncr.textContent = ncrOption.name;
                    ncr.dataset.name = ncrOption.name;
                    ncr.dataset.type = ncrOption.type;
                    provinceSelect.appendChild(ncr);

                    provinces.forEach(function (province) {
                        const option = document.createElement('option');
                        option.value = province.code;
                        option.textContent = province.name;
                        option.dataset.name = province.name;
                        option.dataset.type = 'province';
                        provinceSelect.appendChild(option);
                    });

                    provinceSelect.dataset.loaded = '1';

                    const matched = findOptionByDefaults(provinceSelect, defaultProvinceCode, defaultProvinceName);

                    if (matched) {
                        provinceSelect.value = matched.value;
                        provinceSelect.dispatchEvent(new Event('change'));
                    }
                } catch (e) {
                    provinceSelect.innerHTML = '<option value="">Unable to load provinces</option>';
                }
            }

            async function loadCities(wrapper, provinceCode, provinceType) {
                const citySelect = wrapper.querySelector('.ourlife-city-select');
                if (!citySelect) return;

                const defaultCityName = wrapper.dataset.defaultCityName || '';
                const defaultCityCode = wrapper.dataset.defaultCityCode || '';

                citySelect.disabled = true;
                citySelect.innerHTML = '<option value="">Loading cities / municipalities...</option>';

                const url = provinceType === 'region'
                    ? 'https://psgc.gitlab.io/api/regions/' + provinceCode + '/cities-municipalities/'
                    : 'https://psgc.gitlab.io/api/provinces/' + provinceCode + '/cities-municipalities/';

                try {
                    let cities = await fetchJson(url);
                    cities = sortByName(cities);

                    citySelect.innerHTML = '<option value="">Select City / Municipality</option>';

                    cities.forEach(function (city) {
                        const option = document.createElement('option');
                        option.value = city.code;
                        option.textContent = city.name;
                        option.dataset.name = city.name;
                        citySelect.appendChild(option);
                    });

                    citySelect.disabled = false;

                    const matched = findOptionByDefaults(citySelect, defaultCityCode, defaultCityName);

                    if (matched) {
                        citySelect.value = matched.value;
                        citySelect.dispatchEvent(new Event('change'));
                    }
                } catch (e) {
                    citySelect.innerHTML = '<option value="">Unable to load cities</option>';
                }
            }

            document.querySelectorAll('.ourlife-location-group').forEach(function (wrapper) {
                const provinceSelect = wrapper.querySelector('.ourlife-province-select');
                const citySelect = wrapper.querySelector('.ourlife-city-select');
                const provinceName = wrapper.querySelector('.ourlife-province-name');
                const cityName = wrapper.querySelector('.ourlife-city-name');
                const provinceCode = wrapper.querySelector('.ourlife-province-code');
                const cityCode = wrapper.querySelector('.ourlife-city-code');

                if (!provinceSelect || !citySelect) return;

                loadProvinces(wrapper);

                provinceSelect.addEventListener('change', function () {
                    const selected = provinceSelect.options[provinceSelect.selectedIndex];
                    const selectedName = selected ? selected.dataset.name || '' : '';
                    const selectedType = selected ? selected.dataset.type || 'province' : '';

                    provinceName.value = selectedName;
                    provinceCode.value = provinceSelect.value;

                    cityName.value = '';
                    cityCode.value = '';

                    if (!provinceSelect.value) {
                        citySelect.disabled = true;
                        citySelect.innerHTML = '<option value="">Select province first</option>';
                        return;
                    }

                    loadCities(wrapper, provinceSelect.value, selectedType);
                });

                citySelect.addEventListener('change', function () {
                    const selected = citySelect.options[citySelect.selectedIndex];
                    cityName.value = selected ? selected.dataset.name || '' : '';
                    cityCode.value = citySelect.value;
                });
            });
        });
    </script>
    <?php
});

