if (!function_exists('ourlife_submission_success_message')) {
    function ourlife_submission_success_message() {
        if (empty($_GET['ourlife_submitted'])) return '';

        $submitted = sanitize_key(wp_unslash($_GET['ourlife_submitted']));

        if ($submitted === 'company' || $submitted === 'provider') {
            return '<div class="ourlife-alert-success">Company registration received. It is now pending review.</div>';
        }

        if ($submitted === 'agent') {
            return '<div class="ourlife-alert-success">Agent application received. It is now pending review.</div>';
        }

        if ($submitted === 'listing') {
            return '<div class="ourlife-alert-success">Listing submitted. It is now pending review.</div>';
        }

        return '<div class="ourlife-alert-success">Submission received. It is now pending review.</div>';
    }
}

