if (!function_exists('ourlife_term_options_html')) {
    function ourlife_term_options_html($taxonomy, $selected = '') {
        $terms = get_terms([
            'taxonomy'   => $taxonomy,
            'hide_empty' => false,
            'orderby'    => 'name',
            'order'      => 'ASC',
        ]);

        if (is_wp_error($terms) || empty($terms)) return '';

        $html = '';

        foreach ($terms as $term) {
            $html .= '<option value="' . esc_attr($term->term_id) . '" ' . selected((string) $selected, (string) $term->term_id, false) . '>';
            $html .= esc_html($term->name);
            $html .= '</option>';
        }

        return $html;
    }
}

if (!function_exists('ourlife_term_checkboxes_html')) {
    function ourlife_term_checkboxes_html($taxonomy, $field_name, $selected = []) {
        $terms = get_terms([
            'taxonomy'   => $taxonomy,
            'hide_empty' => false,
            'orderby'    => 'name',
            'order'      => 'ASC',
        ]);

        if (is_wp_error($terms) || empty($terms)) {
            return '<p class="ourlife-form-note">No options available yet.</p>';
        }

        $selected = array_map('absint', (array) $selected);
        $html = '<div class="ourlife-checkbox-grid">';

        foreach ($terms as $term) {
            $checked = in_array((int) $term->term_id, $selected, true) ? 'checked' : '';

            $html .= '<label class="ourlife-checkbox">';
            $html .= '<input type="checkbox" name="' . esc_attr($field_name) . '[]" value="' . esc_attr($term->term_id) . '" ' . $checked . '>';
            $html .= '<span>' . esc_html($term->name) . '</span>';
            $html .= '</label>';
        }

        $html .= '</div>';

        return $html;
    }
}

