if (!function_exists('ourlife_build_agent_full_name')) {
    function ourlife_build_agent_full_name($first_name, $middle_initial, $last_name, $suffix) {
        $first_name     = trim($first_name);
        $middle_initial = trim(str_replace('.', '', $middle_initial));
        $last_name      = trim($last_name);
        $suffix         = trim($suffix);

        $name = $first_name;

        if ($middle_initial) $name .= ' ' . $middle_initial . '.';

        $name .= ' ' . $last_name;

        if ($suffix) $name .= ' ' . $suffix;

        return trim(preg_replace('/\s+/', ' ', $name));
    }
}

