add_action('init', function () {
    if (empty($_POST['ourlife_provider_action']) || $_POST['ourlife_provider_action'] !== 'submit_provider') return;

    if (!is_user_logged_in()) {
        wp_die('Please log in to register a company.');
    }

    if (!ourlife_verify_nonce('ourlife_submit_provider')) {
        wp_die('Security check failed.');
    }

    $title = ourlife_get_post_text('provider_name');

    if (!$title) {
        wp_die('Company name is required.');
    }

    $post_id = wp_insert_post([
        'post_type'    => OURLIFE_CPT_PROVIDER,
        'post_title'   => $title,
        'post_content' => ourlife_get_post_textarea('business_description'),
        'post_status'  => 'pending',
        'post_author'  => get_current_user_id(),
    ]);

    if (is_wp_error($post_id) || !$post_id) {
        wp_die('Unable to register company.');
    }

    update_post_meta($post_id, '_provider_type', ourlife_get_post_text('provider_type'));
    update_post_meta($post_id, '_company_type', ourlife_get_post_text('provider_type'));
    update_post_meta($post_id, '_business_description', ourlife_get_post_textarea('business_description'));
    update_post_meta($post_id, '_address', ourlife_get_post_text('address'));
    update_post_meta($post_id, '_city', ourlife_get_post_text('city'));
    update_post_meta($post_id, '_city_code', ourlife_get_post_text('city_code'));
    update_post_meta($post_id, '_province', ourlife_get_post_text('province'));
    update_post_meta($post_id, '_province_code', ourlife_get_post_text('province_code'));
    update_post_meta($post_id, '_contact_number', ourlife_get_post_text('contact_number'));

    if (isset($_POST['email'])) {
        update_post_meta($post_id, '_email', sanitize_email(wp_unslash($_POST['email'])));
    }

    if (isset($_POST['website'])) {
        update_post_meta($post_id, '_website', esc_url_raw(wp_unslash($_POST['website'])));
    }

    update_post_meta($post_id, '_verification_status', 'pending');
    update_post_meta($post_id, '_claim_status', 'claimed');
    update_post_meta($post_id, '_created_by_user', get_current_user_id());

    if (!empty($_POST['provider_type_term'])) {
        wp_set_post_terms($post_id, [absint($_POST['provider_type_term'])], OURLIFE_TAX_PROVIDER_TYPE);
    }

    ourlife_update_user_profile_from_submission(get_current_user_id());

    update_user_meta(get_current_user_id(), 'ourlife_account_status', 'pending_company');
    update_user_meta(get_current_user_id(), 'ourlife_company_application_status', 'pending');
    update_user_meta(get_current_user_id(), 'ourlife_company_status', 'pending');

    /**
     * Legacy provider meta compatibility.
     */
    update_user_meta(get_current_user_id(), 'ourlife_provider_application_status', 'pending');
    update_user_meta(get_current_user_id(), 'ourlife_provider_status', 'pending');

    wp_safe_redirect(add_query_arg('ourlife_submitted', 'company', wp_get_referer() ?: home_url('/')));
    exit;
});

