add_action('init', function () {
    if (empty($_POST['ourlife_listing_action']) || $_POST['ourlife_listing_action'] !== 'submit_listing') return;

    if (!is_user_logged_in()) {
        wp_die('Please log in to submit a listing.');
    }

    if (!ourlife_user_can_create_listing()) {
        wp_die('You do not have permission to create listings.');
    }

    if (!ourlife_verify_nonce('ourlife_submit_listing')) {
        wp_die('Security check failed.');
    }

    $title = ourlife_get_post_text('listing_title');

    if (!$title) {
        wp_die('Listing title is required.');
    }

    $provider_id = isset($_POST['provider_id']) ? absint($_POST['provider_id']) : 0;
    $agent_id    = isset($_POST['agent_id']) ? absint($_POST['agent_id']) : 0;

    if (!$provider_id && !$agent_id) {
        wp_die('Please select a company or agent for this listing.');
    }

    $post_id = wp_insert_post([
        'post_type'    => OURLIFE_CPT_LISTING,
        'post_title'   => $title,
        'post_content' => ourlife_get_post_textarea('description'),
        'post_status'  => 'pending',
        'post_author'  => get_current_user_id(),
    ]);

    if (is_wp_error($post_id) || !$post_id) {
        wp_die('Unable to submit listing.');
    }

    update_post_meta($post_id, '_provider_id', $provider_id);
    update_post_meta($post_id, '_company_id', $provider_id);
    update_post_meta($post_id, '_agent_id', $agent_id);
    update_post_meta($post_id, '_owner_type', ourlife_is_agent() ? 'agent' : 'company');
    update_post_meta($post_id, '_owner_user_id', get_current_user_id());
    update_post_meta($post_id, '_price', isset($_POST['price']) ? ourlife_clean_number($_POST['price']) : 0);
    update_post_meta($post_id, '_monthly_payment', isset($_POST['monthly_payment']) ? ourlife_clean_number($_POST['monthly_payment']) : 0);
    update_post_meta($post_id, '_location_city', ourlife_get_post_text('city'));
    update_post_meta($post_id, '_location_city_code', ourlife_get_post_text('city_code'));
    update_post_meta($post_id, '_location_province', ourlife_get_post_text('province'));
    update_post_meta($post_id, '_location_province_code', ourlife_get_post_text('province_code'));
    update_post_meta($post_id, '_address', ourlife_get_post_text('address'));
    update_post_meta($post_id, '_availability', isset($_POST['availability']) ? sanitize_key(wp_unslash($_POST['availability'])) : 'available');
    update_post_meta($post_id, '_listing_status', 'pending');
    update_post_meta($post_id, '_featured_status', 'none');
    update_post_meta($post_id, '_features', ourlife_get_post_textarea('features'));
    update_post_meta($post_id, '_capacity', ourlife_get_post_text('capacity'));
    update_post_meta($post_id, '_last_updated', current_time('mysql'));

    if (!empty($_POST['listing_category_term'])) {
        wp_set_post_terms($post_id, [absint($_POST['listing_category_term'])], OURLIFE_TAX_LISTING_CATEGORY);
    }

    if (!empty($_POST['listing_type_term'])) {
        wp_set_post_terms($post_id, [absint($_POST['listing_type_term'])], OURLIFE_TAX_LISTING_TYPE);
    }

    if (!empty($_POST['price_range_term'])) {
        wp_set_post_terms($post_id, [absint($_POST['price_range_term'])], OURLIFE_TAX_PRICE_RANGE);
    }

    ourlife_update_user_profile_from_submission(get_current_user_id());

    wp_safe_redirect(add_query_arg('ourlife_submitted', 'listing', wp_get_referer() ?: home_url('/')));
    exit;
});

