/* =====================================================
 * COMPANY ROLE HELPER
 * ===================================================== */

if (!function_exists('ourlife_is_company')) {
    function ourlife_is_company($user_id = 0) {
        $user = $user_id ? get_user_by('id', absint($user_id)) : wp_get_current_user();

        if (!$user) {
            return false;
        }

        return in_array(OURLIFE_ROLE_COMPANY, (array) $user->roles, true) ||
               in_array('ourlife_provider', (array) $user->roles, true);
    }
}

/**
 * Legacy alias.
 */
if (!function_exists('ourlife_is_provider')) {
    function ourlife_is_provider($user_id = 0) {
        return ourlife_is_company($user_id);
    }
}

/* =====================================================
 * DASHBOARD AVATAR HELPERS
 * ===================================================== */

if (!function_exists('ourlife_get_user_avatar_url')) {
    function ourlife_get_user_avatar_url($user_id = 0) {
        $user_id = $user_id ?: get_current_user_id();

        if (!$user_id) {
            return '';
        }

        $avatar_id = absint(get_user_meta($user_id, 'ourlife_profile_photo_id', true));

        if (!$avatar_id) {
            $avatar_id = absint(get_user_meta($user_id, 'ourlife_avatar_id', true));
        }

        if ($avatar_id) {
            $url = wp_get_attachment_image_url($avatar_id, 'thumbnail');

            if ($url) {
                return $url;
            }
        }

        return '';
    }
}

if (!function_exists('ourlife_render_user_profile_photo')) {
    function ourlife_render_user_profile_photo($user_id = 0) {
        $user_id = $user_id ?: get_current_user_id();

        $custom_avatar = ourlife_get_user_avatar_url($user_id);

        if ($custom_avatar) {
            return '<img class="ourlife-profile-photo" src="' . esc_url($custom_avatar) . '" alt="Profile photo">';
        }

        return get_avatar($user_id, 132, '', 'Profile photo', [
            'class' => 'ourlife-profile-photo',
        ]);
    }
}

add_filter('get_avatar_url', function ($url, $id_or_email, $args) {
    $user = false;

    if (is_numeric($id_or_email)) {
        $user = get_user_by('id', absint($id_or_email));
    } elseif ($id_or_email instanceof WP_User) {
        $user = $id_or_email;
    } elseif ($id_or_email instanceof WP_Comment) {
        if (!empty($id_or_email->user_id)) {
            $user = get_user_by('id', absint($id_or_email->user_id));
        }
    } elseif (is_string($id_or_email)) {
        $user = get_user_by('email', $id_or_email);
    }

    if (!$user || empty($user->ID)) {
        return $url;
    }

    $custom_avatar = ourlife_get_user_avatar_url($user->ID);

    return $custom_avatar ?: $url;
}, 10, 3);

