 * ===================================================== */

add_action('init', function () {
    if (empty($_POST['ourlife_account_action']) || $_POST['ourlife_account_action'] !== 'update_account') {
        return;
    }

    if (!is_user_logged_in()) {
        wp_die('Please log in to update your account.');
    }

    if (
        !isset($_POST['_ourlife_account_nonce']) ||
        !wp_verify_nonce(sanitize_text_field(wp_unslash($_POST['_ourlife_account_nonce'])), 'ourlife_update_account')
    ) {
        wp_die('Security check failed.');
    }

    $user_id = get_current_user_id();

    $first_name = sanitize_text_field(wp_unslash($_POST['first_name'] ?? ''));
    $last_name  = sanitize_text_field(wp_unslash($_POST['last_name'] ?? ''));
    $display    = sanitize_text_field(wp_unslash($_POST['display_name'] ?? ''));
    $email      = sanitize_email(wp_unslash($_POST['email'] ?? ''));

    if (!$first_name || !$last_name || !$display || !$email || !is_email($email)) {
        wp_safe_redirect(add_query_arg('account_error', 'missing', home_url('/dashboard/?view=settings')));
        exit;
    }

    $existing = email_exists($email);

    if ($existing && intval($existing) !== intval($user_id)) {
        wp_safe_redirect(add_query_arg('account_error', 'email_exists', home_url('/dashboard/?view=settings')));
        exit;
    }

    $updated = wp_update_user([
        'ID'           => $user_id,
        'first_name'   => $first_name,
        'last_name'    => $last_name,
        'display_name' => $display,
        'user_email'   => $email,
    ]);

    if (is_wp_error($updated)) {
        wp_safe_redirect(add_query_arg('account_error', 'failed', home_url('/dashboard/?view=settings')));
        exit;
    }

    update_user_meta($user_id, 'ourlife_middle_initial', sanitize_text_field(wp_unslash($_POST['middle_initial'] ?? '')));
    update_user_meta($user_id, 'ourlife_suffix', sanitize_text_field(wp_unslash($_POST['suffix'] ?? '')));
    update_user_meta($user_id, 'ourlife_mobile', sanitize_text_field(wp_unslash($_POST['mobile'] ?? '')));
    update_user_meta($user_id, 'ourlife_province', sanitize_text_field(wp_unslash($_POST['province'] ?? '')));
    update_user_meta($user_id, 'ourlife_city', sanitize_text_field(wp_unslash($_POST['city'] ?? '')));

    if (!empty($_FILES['ourlife_avatar']['name'])) {
        if (!function_exists('media_handle_upload')) {
            require_once ABSPATH . 'wp-admin/includes/image.php';
            require_once ABSPATH . 'wp-admin/includes/file.php';
            require_once ABSPATH . 'wp-admin/includes/media.php';
        }

        $file_name = sanitize_file_name($_FILES['ourlife_avatar']['name']);
        $file_type = wp_check_filetype($file_name);

        $allowed = [
            'jpg'  => 'image/jpeg',
            'jpeg' => 'image/jpeg',
            'png'  => 'image/png',
            'webp' => 'image/webp',
        ];

        $ext = strtolower($file_type['ext'] ?? '');

        if (!$ext || !isset($allowed[$ext])) {
            wp_safe_redirect(add_query_arg('account_error', 'image_type', home_url('/dashboard/?view=settings')));
            exit;
        }

        $attachment_id = media_handle_upload('ourlife_avatar', 0);

        if (is_wp_error($attachment_id)) {
            wp_safe_redirect(add_query_arg('account_error', 'avatar_failed', home_url('/dashboard/?view=settings')));
            exit;
        }

        update_user_meta($user_id, 'ourlife_profile_photo_id', absint($attachment_id));
        update_user_meta($user_id, 'ourlife_avatar_id', absint($attachment_id));
    }

    wp_safe_redirect(add_query_arg('account_updated', '1', home_url('/dashboard/?view=settings')));
    exit;
});

