/* =====================================================
 * LEAD QUERY HELPER
 * ===================================================== */

if (!function_exists('ourlife_get_leads')) {
    function ourlife_get_leads($args = []) {
        global $wpdb;

        $defaults = [
            'consumer_id' => 0,
            'agent_id'    => 0,
            'company_id'  => 0,
            'provider_id' => 0,
            'limit'       => 20,
        ];

        $args = wp_parse_args($args, $defaults);

        if (!empty($args['company_id']) && empty($args['provider_id'])) {
            $args['provider_id'] = $args['company_id'];
        }

        $where = ['1=1'];
        $values = [];

        if (!empty($args['consumer_id'])) {
            $where[] = 'consumer_id = %d';
            $values[] = absint($args['consumer_id']);
        }

        if (!empty($args['agent_id'])) {
            $where[] = 'agent_id = %d';
            $values[] = absint($args['agent_id']);
        }

        if (!empty($args['provider_id'])) {
            $where[] = 'provider_id = %d';
            $values[] = absint($args['provider_id']);
        }

        $limit = absint($args['limit']);
        $sql = "SELECT * FROM " . ourlife_table('leads') . " WHERE " . implode(' AND ', $where) . " ORDER BY created_at DESC LIMIT {$limit}";

        if (!empty($values)) {
            $sql = $wpdb->prepare($sql, $values);
        }

        return $wpdb->get_results($sql);
    }
}

