/* =====================================================
 * COUNT HELPERS
 * =====================================================
 */

if (!function_exists('ourlife_count_posts_by_status')) {
    function ourlife_count_posts_by_status($post_type, $status = 'publish') {
        $counts = wp_count_posts($post_type);

        return isset($counts->{$status}) ? intval($counts->{$status}) : 0;
    }
}

if (!function_exists('ourlife_count_leads')) {
    function ourlife_count_leads($status = '') {
        global $wpdb;

        $table = ourlife_table('leads');

        if ($status) {
            return intval($wpdb->get_var(
                $wpdb->prepare(
                    "SELECT COUNT(*) FROM {$table} WHERE status = %s",
                    sanitize_key($status)
                )
            ));
        }

        return intval($wpdb->get_var("SELECT COUNT(*) FROM {$table}"));
    }
}

