 * HEALTH STATUS HELPER
 * =====================================================
 */

if (!function_exists('ourlife_health_status')) {
    function ourlife_health_status($condition, $ok = 'OK', $bad = 'Needs Attention') {
        if ($condition) {
            return '<span class="ourlife-health-status ourlife-ok">✅ ' . esc_html($ok) . '</span>';
        }

        return '<span class="ourlife-health-status ourlife-bad">⚠️ ' . esc_html($bad) . '</span>';
    }
}

