if (!function_exists('ourlife_home_latest_cards')) {
    function ourlife_home_latest_cards($args = []) {
        if (!defined('OURLIFE_CPT_LISTING') || !function_exists('ourlife_render_listing_card')) {
            return '<div class="ol-placeholder-card">Featured listings will appear here once your marketplace listing module is active.</div>';
        }

        $defaults = [
            'post_type'      => OURLIFE_CPT_LISTING,
            'posts_per_page' => 3,
            'post_status'    => 'publish',
        ];

        $args = wp_parse_args($args, $defaults);
        $q = new WP_Query($args);

        if (!$q->have_posts()) {
            return '<div class="ol-placeholder-card">Listings will appear here once published.</div>';
        }

        ob_start();
        ?>
        <div class="ol-card-grid">
            <?php while ($q->have_posts()) : $q->the_post(); ?>
                <?php echo ourlife_render_listing_card(get_the_ID()); ?>
            <?php endwhile; ?>
        </div>
        <?php
        wp_reset_postdata();
        return ob_get_clean();
    }
}

if (!function_exists('ourlife_home_profile_avatar')) {
    function ourlife_home_profile_avatar($user_id, $title) {
        $user_id = absint($user_id);

        if (!$user_id) {
            return '<div class="ol-avatar" style="display:flex;align-items:center;justify-content:center;background:#EEF4F8;color:#0E2B4C;font-weight:900;">' . esc_html(mb_substr($title, 0, 1)) . '</div>';
        }

        return get_avatar(
            $user_id,
            96,
            '',
            $title,
            ['class' => 'ol-avatar']
        );
    }
}

if (!function_exists('ourlife_home_company_agent_preview')) {
    function ourlife_home_company_agent_preview($post_type, $limit = 3) {
        if (!$post_type) {
            return '<div class="ol-placeholder-card">Profiles will appear here once approved.</div>';
        }

        $q = new WP_Query([
            'post_type'      => $post_type,
            'posts_per_page' => absint($limit),
            'post_status'    => 'publish',
        ]);

        if (!$q->have_posts()) {
            return '<div class="ol-placeholder-card">Profiles will appear here once approved.</div>';
        }

        ob_start();
        ?>
        <div class="ol-mini-grid">
            <?php while ($q->have_posts()) : $q->the_post(); ?>
                <?php
                $id = get_the_ID();
                $is_company = defined('OURLIFE_CPT_PROVIDER') && $post_type === OURLIFE_CPT_PROVIDER;

                $city = $is_company ? get_post_meta($id, '_city', true) : get_post_meta($id, '_location_city', true);
                $province = $is_company ? get_post_meta($id, '_province', true) : get_post_meta($id, '_location_province', true);
                $verified = get_post_meta($id, '_verification_status', true);

                $user_id = $is_company
                    ? absint(get_post_meta($id, '_created_by_user', true))
                    : absint(get_post_meta($id, '_user_id', true));
                ?>

                <article class="ol-mini-card">
                    <div class="ol-mini-profile">
                        <div class="ol-profile-photo">
                            <?php echo ourlife_home_profile_avatar($user_id, get_the_title()); ?>
                        </div>

                        <div>
                            <h4>
                                <a href="<?php the_permalink(); ?>">
                                    <?php the_title(); ?>
                                </a>
                            </h4>

                            <?php if (function_exists('ourlife_format_location')) : ?>
                                <p><?php echo esc_html(ourlife_format_location($city, $province)); ?></p>
                            <?php else : ?>
                                <p><?php echo esc_html(trim($city . ', ' . $province, ', ')); ?></p>
                            <?php endif; ?>
                        </div>
                    </div>

                    <div class="ol-mini-meta">
                        <?php if ($verified === 'verified') : ?>
                            <span class="ol-mini-pill">
                                <?php echo $is_company ? 'Verified Company' : 'Verified Agent'; ?>
                            </span>
                        <?php endif; ?>

                        <span class="ol-mini-pill">
                            <?php echo $is_company ? 'Company Profile' : 'Agent Profile'; ?>
                        </span>
                    </div>

                    <a class="ol-mini-action" href="<?php the_permalink(); ?>">
                        View Profile →
                    </a>
                </article>
            <?php endwhile; ?>
        </div>
        <?php
        wp_reset_postdata();
        return ob_get_clean();
    }
}

