<script>
document.addEventListener('DOMContentLoaded', function () {
    const mobileToggle = document.querySelector('[data-ol-toggle="#olMobileMenu"]');
    const mobileMenu = document.querySelector('#olMobileMenu');

    function closeMobileMenu() {
        if (!mobileMenu || !mobileToggle) return;
        mobileMenu.classList.remove('active');
        mobileToggle.setAttribute('aria-expanded', 'false');
        mobileToggle.setAttribute('aria-label', 'Open Menu');
    }

    function toggleMobileMenu() {
        if (!mobileMenu || !mobileToggle) return;
        const isOpen = mobileMenu.classList.toggle('active');
        mobileToggle.setAttribute('aria-expanded', isOpen ? 'true' : 'false');
        mobileToggle.setAttribute('aria-label', isOpen ? 'Close Menu' : 'Open Menu');
    }

    if (mobileToggle) {
        mobileToggle.addEventListener('click', function (event) {
            event.preventDefault();
            event.stopPropagation();
            toggleMobileMenu();
        });
    }

    if (mobileMenu) {
        mobileMenu.querySelectorAll('a').forEach(function (link) {
            link.addEventListener('click', closeMobileMenu);
        });
    }

    document.addEventListener('click', function (event) {
        if (!mobileMenu || !mobileToggle) return;
        if (!mobileMenu.contains(event.target) && !mobileToggle.contains(event.target)) {
            closeMobileMenu();
        }
    });

    document.addEventListener('keydown', function (event) {
        if (event.key === 'Escape') {
            closeMobileMenu();

            document.querySelectorAll('.ol-nav-item.is-open, .ol-account.is-open').forEach(function (item) {
                item.classList.remove('is-open');
            });
        }
    });

    document.querySelectorAll('.ol-nav-trigger').forEach(function (button) {
        button.setAttribute('aria-expanded', 'false');

        button.addEventListener('click', function (event) {
            const navItem = button.closest('.ol-nav-item');
            if (!navItem) return;

            event.preventDefault();
            event.stopPropagation();

            document.querySelectorAll('.ol-nav-item.is-open').forEach(function (item) {
                if (item !== navItem) {
                    item.classList.remove('is-open');

                    const trigger = item.querySelector('.ol-nav-trigger');
                    if (trigger) trigger.setAttribute('aria-expanded', 'false');
                }
            });

            const isOpen = navItem.classList.toggle('is-open');
            button.setAttribute('aria-expanded', isOpen ? 'true' : 'false');
        });
    });

    const accountTrigger = document.querySelector('.ol-account-trigger');

    if (accountTrigger) {
        accountTrigger.setAttribute('aria-expanded', 'false');

        accountTrigger.addEventListener('click', function (event) {
            const account = accountTrigger.closest('.ol-account');
            if (!account) return;

            event.preventDefault();
            event.stopPropagation();

            const isOpen = account.classList.toggle('is-open');
            accountTrigger.setAttribute('aria-expanded', isOpen ? 'true' : 'false');
        });
    }

    document.addEventListener('click', function () {
        document.querySelectorAll('.ol-nav-item.is-open').forEach(function (item) {
            item.classList.remove('is-open');

            const trigger = item.querySelector('.ol-nav-trigger');
            if (trigger) trigger.setAttribute('aria-expanded', 'false');
        });

        document.querySelectorAll('.ol-account.is-open').forEach(function (item) {
            item.classList.remove('is-open');

            const trigger = item.querySelector('.ol-account-trigger');
            if (trigger) trigger.setAttribute('aria-expanded', 'false');
        });
    });
});
</script>
