add_action('init', function () {
    if (empty($_POST['ourlife_register_action']) || $_POST['ourlife_register_action'] !== 'register') {
        return;
    }

    if (!isset($_POST['_ourlife_register_nonce']) || !wp_verify_nonce(sanitize_text_field(wp_unslash($_POST['_ourlife_register_nonce'])), 'ourlife_register_user')) {
        wp_die('Security check failed.');
    }

    $first_name = sanitize_text_field(wp_unslash($_POST['first_name'] ?? ''));
    $middle_initial = sanitize_text_field(wp_unslash($_POST['middle_initial'] ?? ''));
    $last_name = sanitize_text_field(wp_unslash($_POST['last_name'] ?? ''));
    $suffix = sanitize_text_field(wp_unslash($_POST['suffix'] ?? ''));

    $email = sanitize_email(wp_unslash($_POST['email'] ?? ''));
    $mobile = sanitize_text_field(wp_unslash($_POST['mobile'] ?? ''));
    $password = (string) ($_POST['password'] ?? '');
    $confirm_password = (string) ($_POST['confirm_password'] ?? '');

    $province = sanitize_text_field(wp_unslash($_POST['province'] ?? ''));
    $city = sanitize_text_field(wp_unslash($_POST['city'] ?? ''));
    $purpose = sanitize_key(wp_unslash($_POST['purpose'] ?? ''));

    $allowed_purposes = [
        'planning_ahead',
        'need_help_now',
        'agent',
        'provider',
    ];

    if (!$first_name || !$last_name || !$email || !$password || !$purpose) {
        wp_safe_redirect(add_query_arg('ol_reg_error', 'missing', wp_get_referer() ?: home_url('/register/')));
        exit;
    }

    if (!in_array($purpose, $allowed_purposes, true)) {
        wp_safe_redirect(add_query_arg('ol_reg_error', 'purpose', wp_get_referer() ?: home_url('/register/')));
        exit;
    }

    if (!is_email($email)) {
        wp_safe_redirect(add_query_arg('ol_reg_error', 'email', wp_get_referer() ?: home_url('/register/')));
        exit;
    }

    if ($password !== $confirm_password) {
        wp_safe_redirect(add_query_arg('ol_reg_error', 'password', wp_get_referer() ?: home_url('/register/')));
        exit;
    }

    if (email_exists($email)) {
        wp_safe_redirect(add_query_arg('ol_reg_error', 'exists', wp_get_referer() ?: home_url('/register/')));
        exit;
    }

    $username_base = sanitize_user(strtolower($first_name . '.' . $last_name));
    $username = $username_base;
    $i = 1;

    while (username_exists($username)) {
        $username = $username_base . $i;
        $i++;
    }

    $user_id = wp_create_user($username, $password, $email);

    if (is_wp_error($user_id)) {
        wp_safe_redirect(add_query_arg('ol_reg_error', 'failed', wp_get_referer() ?: home_url('/register/')));
        exit;
    }

    wp_update_user([
        'ID'           => $user_id,
        'first_name'   => $first_name,
        'last_name'    => $last_name,
        'display_name' => trim($first_name . ' ' . $last_name),
        'role'         => 'subscriber',
    ]);

    update_user_meta($user_id, 'ourlife_middle_initial', $middle_initial);
    update_user_meta($user_id, 'ourlife_suffix', $suffix);
    update_user_meta($user_id, 'ourlife_mobile', $mobile);
    update_user_meta($user_id, 'ourlife_province', $province);
    update_user_meta($user_id, 'ourlife_city', $city);
    update_user_meta($user_id, 'ourlife_joining_purpose', $purpose);
    update_user_meta($user_id, 'ourlife_onboarding_status', 'started');

    if ($purpose === 'agent') {
        update_user_meta($user_id, 'ourlife_agent_application_status', 'not_started');
    }

    if ($purpose === 'provider') {
        update_user_meta($user_id, 'ourlife_provider_application_status', 'not_started');
    }

    wp_set_current_user($user_id);
    wp_set_auth_cookie($user_id);

    wp_safe_redirect(home_url('/onboarding/'));
    exit;
});

