if (!function_exists('ourlife_login_url')) {
    function ourlife_login_url($redirect = '') {
        $url = home_url('/login/');

        if ($redirect) {
            $url = add_query_arg('redirect_to', rawurlencode($redirect), $url);
        }

        return esc_url($url);
    }
}

if (!function_exists('ourlife_after_login_redirect')) {
    function ourlife_after_login_redirect() {
        if (!empty($_REQUEST['redirect_to'])) {
            return esc_url_raw(wp_unslash($_REQUEST['redirect_to']));
        }

        if (current_user_can('manage_options')) {
            return admin_url();
        }

        return home_url('/dashboard/');
    }
}

/* =====================================================
 * ALLOW EMAIL LOGIN
 * ===================================================== */

add_filter('authenticate', function ($user, $username, $password) {
    if ($user instanceof WP_User || empty($username)) {
        return $user;
    }

    if (is_email($username)) {
        $user_obj = get_user_by('email', $username);

        if ($user_obj) {
            $username = $user_obj->user_login;
        }
    }

    return wp_authenticate_username_password(null, $username, $password);
}, 20, 3);

/* =====================================================
 * LOGIN REDIRECT
 * ===================================================== */

add_filter('login_redirect', function ($redirect_to, $requested_redirect_to, $user) {
    if (!($user instanceof WP_User)) {
        return $redirect_to;
    }

    if ($requested_redirect_to) {
        return $requested_redirect_to;
    }

    if (user_can($user, 'manage_options')) {
        return admin_url();
    }

    return home_url('/dashboard/');
}, 10, 3);

