add_action('template_redirect', function () {
    if (is_user_logged_in()) {
        return;
    }

    $protected_paths = [
        'dashboard',
        'submit-provider',
        'submit-agent',
        'submit-listing',
        'onboarding',
    ];

    $current_path = trim(parse_url($_SERVER['REQUEST_URI'] ?? '', PHP_URL_PATH), '/');

    foreach ($protected_paths as $path) {
        if ($current_path === $path || str_starts_with($current_path, $path . '/')) {
            wp_safe_redirect(ourlife_login_url(home_url('/' . $current_path . '/')));
            exit;
        }
    }
});

