/* =====================================================
 * ROLE UPGRADE HELPERS
 * ===================================================== */

if (!function_exists('ourlife22_set_user_role')) {
    function ourlife22_set_user_role($user_id, $role) {
        $user = get_user_by('id', absint($user_id));

        if (!$user) return false;

        $allowed = [
            OURLIFE_ROLE_CONSUMER,
            OURLIFE_ROLE_AGENT,
            OURLIFE_ROLE_COMPANY,
            OURLIFE_ROLE_ADMIN,
        ];

        if (!in_array($role, $allowed, true)) {
            return false;
        }

        $user->set_role($role);

        return true;
    }
}

if (!function_exists('ourlife22_approve_agent')) {
    function ourlife22_approve_agent($user_id) {
        $user_id = absint($user_id);

        if (!$user_id) return false;

        ourlife22_set_user_role($user_id, OURLIFE_ROLE_AGENT);

        update_user_meta($user_id, 'ourlife_account_status', 'active');
        update_user_meta($user_id, 'ourlife_agent_status', 'verified');
        update_user_meta($user_id, 'ourlife_agent_verified', 1);
        update_user_meta($user_id, 'ourlife_agent_verified_at', current_time('mysql'));
        update_user_meta($user_id, 'ourlife_agent_verified_by', get_current_user_id());

        return true;
    }
}

if (!function_exists('ourlife22_approve_company')) {
    function ourlife22_approve_company($user_id) {
        $user_id = absint($user_id);

        if (!$user_id) return false;

        ourlife22_set_user_role($user_id, OURLIFE_ROLE_COMPANY);

        update_user_meta($user_id, 'ourlife_account_status', 'active');

        update_user_meta($user_id, 'ourlife_company_status', 'verified');
        update_user_meta($user_id, 'ourlife_company_verified', 1);
