/* =====================================================
 * ACTION HANDLER
 * ===================================================== */

add_action('init', function () {
    if (empty($_POST['ourlife22_action'])) return;

    if (!is_user_logged_in() || !ourlife22_is_admin()) {
        return;
    }

    if (
        empty($_POST['_ourlife22_nonce']) ||
        !wp_verify_nonce(
            sanitize_text_field(wp_unslash($_POST['_ourlife22_nonce'])),
            'ourlife22_approval_action'
        )
    ) {
        return;
    }

    $action  = sanitize_key(wp_unslash($_POST['ourlife22_action']));
    $user_id = isset($_POST['ourlife22_user_id']) ? absint($_POST['ourlife22_user_id']) : 0;
    $reason  = isset($_POST['ourlife22_reason']) ? sanitize_textarea_field(wp_unslash($_POST['ourlife22_reason'])) : '';

    if (!$user_id) return;

    if ($action === 'approve_agent') {
        ourlife22_approve_agent($user_id);
        wp_safe_redirect(add_query_arg('ourlife22_notice', 'agent_approved', wp_get_referer()));
        exit;
    }

    if ($action === 'reject_agent') {
        ourlife22_reject_agent($user_id, $reason);
        wp_safe_redirect(add_query_arg('ourlife22_notice', 'agent_rejected', wp_get_referer()));
        exit;
    }

    if ($action === 'approve_company' || $action === 'approve_provider') {
        ourlife22_approve_company($user_id);
        wp_safe_redirect(add_query_arg('ourlife22_notice', 'company_approved', wp_get_referer()));
        exit;
    }

    if ($action === 'reject_company' || $action === 'reject_provider') {
        ourlife22_reject_company($user_id, $reason);
        wp_safe_redirect(add_query_arg('ourlife22_notice', 'company_rejected', wp_get_referer()));
        exit;
    }
});

