/* =====================================================
 * USER FIELD HELPERS
 * ===================================================== */

if (!function_exists('ourlife22_user_meta')) {
    function ourlife22_user_meta($user_id, $key, $default = '—') {
        $value = get_user_meta($user_id, $key, true);
        return $value !== '' ? $value : $default;
    }
}

if (!function_exists('ourlife22_first_available_meta')) {
    function ourlife22_first_available_meta($user_id, $keys, $default = '—') {
        foreach ((array) $keys as $key) {
            $value = get_user_meta($user_id, $key, true);

            if ($value !== '') {
                return $value;
            }
        }

        return $default;
    }
}

if (!function_exists('ourlife22_user_name')) {
    function ourlife22_user_name($user) {
        $first  = get_user_meta($user->ID, 'first_name', true);
        $middle = get_user_meta($user->ID, 'ourlife_middle_initial', true);
        $last   = get_user_meta($user->ID, 'last_name', true);
        $suffix = get_user_meta($user->ID, 'ourlife_suffix', true);

        $name = trim(implode(' ', array_filter([$first, $middle, $last, $suffix])));

        return $name ?: $user->display_name;
    }
}

